<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">set</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> set-clipboard</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> on</span></span>
